import * as React from 'react';
import { createComponent } from '../create-component.js';
import Component from '../../components/icon/src/icon.component.js';
const tagName = 'made-icon';
Component.define('made-icon');
/**
 * @summary Icons are symbols that can be used to represent various options within an application.
 * @documentation '../../components/icon/stories/icon.mdx'
 *
 * @fires mde-load {CustomEvent} - Fired when the icon has loaded.
 * @fires mde-error {CustomEvent} - Fired when the icon fails to load due to an error.
 *
 * @csspart base - The component's base wrapper.
 * @csspart svg - The internal SVG element.
 */
const reactWrapper = createComponent({
    tagName,
    elementClass: Component,
    react: React,
    events: {
        onMdeLoad: 'mde-load',
        onMdeError: 'mde-error'
    },
    displayName: 'MadeIcon'
});
export default reactWrapper;
